from enum import Enum
from typing import Tuple, Dict


class ALUOp(Enum):
    ADD = 'add'
    SUB = 'sub'
    AND = 'and'
    OR = 'or'
    XOR = 'xor'
    NOT = 'not'
    SLT = 'slt'
    SLL = 'sll'
    SRL = 'srl'
    SRA = 'sra'


class ALU:
    """8-bit ALU with condition flags."""

    BITS = 8
    MASK = 0xFF
    SIGN_BIT = 0x80

    def _to_signed(self, value: int) -> int:
        """Convert 8-bit unsigned to signed two's complement."""
        if value & self.SIGN_BIT:
            return value - 256
        return value

    def _compute_flags(
        self, result: int, a: int, b: int,
        carry: int, is_arithmetic: bool
    ) -> Dict[str, int]:
        """Compute condition flags."""
        masked = result & self.MASK
        flags = {
            'Z': 1 if masked == 0 else 0,
            'N': 1 if masked & self.SIGN_BIT else 0,
            'V': 0,
            'C': 0,
        }

        if is_arithmetic:
            flags['C'] = carry
            # Overflow: signs of operands are same but result sign differs
            a_sign = (a >> 7) & 1
            b_sign = (b >> 7) & 1
            r_sign = (masked >> 7) & 1
            # For addition: overflow if a and b same sign but result different
            flags['V'] = 1 if (a_sign == b_sign) and (r_sign != a_sign) else 0

        return flags

    def execute(
        self, a: int, b: int, op: ALUOp
    ) -> Tuple[int, Dict[str, int]]:
        """Execute an ALU operation."""
        a = a & self.MASK
        b = b & self.MASK

        if op == ALUOp.ADD:
            full_result = a + b
            carry = 1 if full_result > self.MASK else 0
            result = full_result & self.MASK
            flags = self._compute_flags(result, a, b, carry, True)
            return (result, flags)

        elif op == ALUOp.SUB:
            # a - b = a + (~b) + 1
            b_inv = (~b) & self.MASK
            full_result = a + b_inv + 1
            carry = 1 if full_result > self.MASK else 0
            result = full_result & self.MASK
            # For overflow detection in SUB, treat as adding a + (-b)
            flags = self._compute_flags(result, a, b_inv, carry, True)
            return (result, flags)

        elif op == ALUOp.AND:
            result = a & b
            flags = self._compute_flags(result, a, b, 0, False)
            return (result, flags)

        elif op == ALUOp.OR:
            result = a | b
            flags = self._compute_flags(result, a, b, 0, False)
            return (result, flags)

        elif op == ALUOp.XOR:
            result = a ^ b
            flags = self._compute_flags(result, a, b, 0, False)
            return (result, flags)

        elif op == ALUOp.NOT:
            result = (~a) & self.MASK
            flags = self._compute_flags(result, a, 0, 0, False)
            return (result, flags)

        elif op == ALUOp.SLT:
            # Signed less than: compare as two's complement
            sa = self._to_signed(a)
            sb = self._to_signed(b)
            result = 1 if sa < sb else 0
            flags = self._compute_flags(result, a, b, 0, False)
            return (result, flags)

        elif op == ALUOp.SLL:
            shamt = b & 0x7  # Shift amount 0-7
            result = (a << shamt) & self.MASK
            flags = self._compute_flags(result, a, b, 0, False)
            return (result, flags)

        elif op == ALUOp.SRL:
            shamt = b & 0x7
            result = (a >> shamt) & self.MASK
            flags = self._compute_flags(result, a, b, 0, False)
            return (result, flags)

        elif op == ALUOp.SRA:
            shamt = b & 0x7
            sa = self._to_signed(a)
            result = (sa >> shamt) & self.MASK
            flags = self._compute_flags(result, a, b, 0, False)
            return (result, flags)

        else:
            raise ValueError(f'Unknown operation: {op}')
